const SENDGRID_API_KEY = 'YOUR_SENDGRID_API_KEY';
const STRIPE_SECRET_KEY = 'YOUR_STRIPE_SECRET_KEY';

// Define a function to handle email sending using SendGrid
async function sendEmail(to, subject, body) {
  const url = `https://api.sendgrid.com/v3/mail/send`;
  const headers = new Headers({
    'Authorization': `Bearer ${SENDGRID_API_KEY}`,
    'Content-Type': 'application/json',
  });
  const data = JSON.stringify({
    personalizations: [
      {
        to: [{ email: to }],
        dynamic_template_data: {
          subject,
          body,
        },
      },
    ],
    from: {
      email: 'your-email@example.com',
    },
    template_id: 'YOUR_SENDGRID_TEMPLATE_ID',
  });
  try {
    const response = await fetch(url, {
      method: 'POST',
      headers,
      body: data,
    });
    if (response.ok) {
      return true;
    } else {
      throw new Error(`Error sending email: ${await response.text()}`);
    }
  } catch (error) {
    console.error('Error sending email:', error);
    return false;
  }
}

